{
  "verses": [
    {
      "n": 1,
      "column": "left",
      "text": "Laufajt manni Laudis\nmannu Mahzibu / at-\ngreeseet fawas Ausis us\nmannas Muttes WalloDu.\n"
    },
    {
      "n": 2,
      "column": "left",
      "text": "Es atdarrischu fawu Mut-\nti ar fakfaneem Wahrdeem/ un\nisrunnaschn Mihklas no wezzeem\nLaifeem.\n"
    },
    {
      "n": 3,
      "column": "left",
      "text": "Ko mehs effam dsirdejſchi/\nun finnam/ un muhsu Tehwi\nmums irr stahstifschi.\n"
    },
    {
      "n": 4,
      "column": "left",
      "text": "Ka mumś to ne buhs win-\nnu Behrneem paſlehpt/ kas wehl\npakkat buhs/ bet iſteikt ta KUN-\nGA teizann Slawu/ un win-\nna Stiprann/ un winna Brih-\nnumus/ ko winſch darrijs.\n"
    },
    {
      "n": 5,
      "column": "left",
      "text": "Jo winſch irr weenn Leezi-\nbu eezehlis eekſch Jehkaba/ un\nweenn Baufibn eekſch Israëka\nlizzis/ ko winſch muhsu Tehweem\npavehlejs/ ka tee tohs faweem\nBehrneem mahzitu.\n"
    },
    {
      "n": 6,
      "column": "left",
      "text": "Ka to finnatu tee Behznah-\nkamee/ tee Behrni / kas wehl\ndsims/ kad tee zelſees/ ka ir tee\nfaweem Behrneem to iſteiktu.\n"
    },
    {
      "n": 7,
      "column": "left",
      "text": "Un ka tee fawu Zerribn us\nDeewu tiktu/ un ta STIP-\nRA DEEWA Darrischanae\nne aismirſtn/ bet winna Paweh-\nleschanns fargatu.\n"
    },
    {
      "n": 8,
      "column": "left",
      "text": "Un ka tee tahdi ne buhtu/\nka winnu Tehwi/ weena atkah-\npaja un pahrgalwiga Tauta/\ntahda Tauta/ kas fawu Sirdi\npastahwigu ne tatsija/ un kurra\n"
    },
    {
      "n": 9,
      "column": "right",
      "text": "Tee Gewraima Behrni/ap-\nbrunnoti Strehlueki ar Stoh-\npeem/ atkahpe Rauschanas Laika.\n"
    },
    {
      "n": 10,
      "column": "right",
      "text": "Tee ne turreja to Deewa\nDerribu / un leedsahs winna\nBaufibā staigahrt.\n"
    },
    {
      "n": 11,
      "column": "right",
      "text": "Un aismirſe winna Dar-\nbus/ un winna Brihnumus/ ko\nwinſch bij parahdijs.\n"
    },
    {
      "n": 12,
      "column": "right",
      "text": "Winnu Tehwu Breckſcha\ndarrija winſch Brihnumus E-\ngiptes Semmē / eekſch Joana\nLanka.\n"
    },
    {
      "n": 13,
      "column": "right",
      "text": "Winſch pahrschſihre to\nJuheu / un likke tohs zaureet/\nun pazehle to Uhdeni stahwu ka\nRohpu.\n"
    },
    {
      "n": 14,
      "column": "right",
      "text": "Un waddija tohs ar Pa-\ndebeſti Deená/ un zaur wiſſu\nNakti ar Ugginė Gaischuinn/\n"
    },
    {
      "n": 15,
      "column": "right",
      "text": "Winſch taplehſe tohs Ak-\nminns Tukneſi/ un dsirdinaja\ntohs papillam (itt ka) no Dsit-\ntumeem.\n"
    },
    {
      "n": 16,
      "column": "right",
      "text": "Winſch arrt iſwedde Up-\npes no Akmiineem/ un likke to\nUhdeni notezzeht ka Straunes.\n"
    },
    {
      "n": 17,
      "column": "right",
      "text": "Tatschu tee wehl wairak\nprett winnu grehkoja/ un apkat-\ntingaja to Wiſnu-ingſtaku Tukſ-\nneſi.\n"
    },
    {
      "n": 18,
      "column": "right",
      "text": "Un tee fahrdinaja Dee-\nwu fawa Sirdi/ Barribn eekah-\nrodami pehz fawas Kahribas.\n"
    },
    {
      "n": 19,
      "column": "right",
      "text": "Un runnaja prett Deewu,\nun fazzia: Warretu tas STIP-\nRAJS DEEWS weenn Gal\ndu fataiſiht Tukneſi?\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
